func (this *BackpackCore) ParseTransaction(transaction any, optionalArgs ...any) any {
	//
	// fetchDeposits
	//     [
	//         {
	//             "createdAt": "2025-07-23T13:55:54.267",
	//             "fiatAmount": null,
	//             "fiatCurrency": null,
	//             "fromAddress": "0x2e3ab3e88a7dbdc763aadf5b28c18fb085af420a",
	//             "id": 6695353,
	//             "institutionBic": null,
	//             "platformMemo": null,
	//             "quantity": "120",
	//             "source": "ethereum",
	//             "status": "confirmed",
	//             "symbol": "USDC",
	//             "toAddress": "0xfBe7CbfCde93c8a4204a4be6B56732Eb32690170",
	//             "transactionHash": "0x58edaac415398d617b34c6673fffcaf0024990d5700565030119db5cbf3765d1"
	//         }
	//     ]
	//
	// withdraw
	//     {
	//         "accountIdentifier": null,
	//         "bankIdentifier": null,
	//         "bankName": null,
	//         "blockchain": "Ethereum",
	//         "clientId": null,
	//         "createdAt": "2025-08-13T19:27:13.817",
	//         "fee": "3",
	//         "fiatFee": null,
	//         "fiatState": null,
	//         "fiatSymbol": null,
	//         "id": 5479929,
	//         "identifier": null,
	//         "isInternal": false,
	//         "providerId": null,
	//         "quantity": "10",
	//         "status": "pending",
	//         "subaccountId": null,
	//         "symbol": "USDC",
	//         "toAddress": "0x0ad42b8e602c2d3d475ae52d678cf63d84ab2749",
	//         "transactionHash": null,
	//         "triggerAt": null
	//     }
	//
	// fetchWithdrawals
	//     [
	//         {
	//             "accountIdentifier": null,
	//             "bankIdentifier": null,
	//             "bankName": null,
	//             "blockchain": "Ethereum",
	//             "clientId": null,
	//             "createdAt": "2025-08-13T19:27:13.817",
	//             "fee": "3",
	//             "fiatFee": null,
	//             "fiatState": null,
	//             "fiatSymbol": null,
	//             "id": 5479929,
	//             "identifier": null,
	//             "isInternal": false,
	//             "providerId": null,
	//             "quantity": "10",
	//             "status": "confirmed",
	//             "subaccountId": null,
	//             "symbol": "USDC",
	//             "toAddress": "0x0ad42b8e602c2d3d475ae52d678cf63d84ab2749",
	//             "transactionHash": "0x658b6d082af4afa0d3cf85caf344ff7c19d980117726bf193b00d8850f8746a1",
	//             "triggerAt": null
	//         }
	//     ]
	//
	currency := GetArg(optionalArgs, 0, nil)
	_ = currency
	var status any = this.ParseTransactionStatus(this.SafeString(transaction, "status"))
	var id any = this.SafeString(transaction, "id")
	var txid any = this.SafeString(transaction, "transactionHash")
	var coin any = this.SafeString(transaction, "symbol")
	var code any = this.SafeCurrencyCode(coin, currency)
	var timestamp any = this.Parse8601(this.SafeString(transaction, "createdAt"))
	var amount any = this.SafeNumber(transaction, "quantity")
	var networkId any = this.SafeStringLower2(transaction, "source", "blockchain")
	var network any = this.NetworkIdToCode(networkId)
	var addressTo any = this.SafeString(transaction, "toAddress")
	var addressFrom any = this.SafeString(transaction, "fromAddress")
	var tag any = this.SafeString(transaction, "platformMemo")
	var feeCost any = this.SafeNumber(transaction, "fee")
	var internal any = this.SafeBool(transaction, "isInternal", false)
	var fee any = nil
	if IsTrue(!IsEqual(feeCost, nil)) {
		fee = map[string]any{
			"cost":     feeCost,
			"currency": code,
		}
	}
	return map[string]any{
		"info":        transaction,
		"id":          id,
		"txid":        txid,
		"timestamp":   timestamp,
		"datetime":    this.Iso8601(timestamp),
		"network":     network,
		"address":     nil,
		"addressTo":   addressTo,
		"addressFrom": addressFrom,
		"tag":         tag,
		"tagTo":       nil,
		"tagFrom":     nil,
		"type":        nil,
		"amount":      amount,
		"currency":    code,
		"status":      status,
		"updated":     nil,
		"internal":    internal,
		"comment":     nil,
		"fee":         fee,
	}
}
func (this *BackpackCore) ParseTransactionStatus(status any) any {
	var statuses any = map[string]any{
		"cancelled":            "cancelled",
		"confirmed":            "ok",
		"declined":             "declined",
		"expired":              "expired",
		"initiated":            "initiated",
		"pending":              "pending",
		"refunded":             "refunded",
		"information required": "pending",
	}
	return this.SafeString(statuses, status, status)
}

